public int findMaxOdd(int i, int[] nums)
{
    int maxOdd;
    maxOdd = 0;

    for (int b = i; b < nums.length - 1; b++)
    {
        if (nums[b] % 2 != 0 && nums[b] > maxOdd)
        {
            maxOdd = nums[b];
            nums[i] = nums[b];
        }
    }
    return maxOdd;
}

public int centeredAverage(int[] nums)
{
    int average = 0;
    int sum = 0;
    int low = nums[0];
    int high = nums[0];
    boolean found = false;

    for (int i = 0; i < nums.length; i++)
    {
        if (nums[i] > high)
        {
            high = nums[i];
        }

        if (nums[i] < low)
        {
            low = nums[i];
        }
    }

    for (int a : nums)
    {
        sum = sum + a;
    }

    sum = sum - low - high;

    average = sum / (nums.length - 2)

    return average;
}

